final class PromoLinkHandler {
    static let shared = PromoLinkHandler()

    private init() {}

    @discardableResult
    func handle(url: URL) -> Bool {
        guard let components = URLComponents(url: url, resolvingAgainstBaseURL: false) else { return false }

        guard let host = components.host?.lowercased(), host == "myapp.com" else { return false }
        guard components.path.lowercased() == "/promo" else { return false }

        let queryItems = components.queryItems ?? []
        let code = queryItems.first(where: { $0.name.lowercased() == "code" })?.value?.trimmingCharacters(in: .whitespacesAndNewlines)
        let discountString = queryItems.first(where: { $0.name.lowercased() == "discount" })?.value?.trimmingCharacters(in: .whitespacesAndNewlines)

        guard let codeUnwrapped = code, !codeUnwrapped.isEmpty else { return false }
        guard let discountStr = discountString, let discount = Int(discountStr) else { return false }
        guard (1...100).contains(discount) else { return false }

        PromoStore.shared.applyPromo(code: codeUnwrapped, discountPercent: discount, sourceURL: url)
        return true
    }
}

struct Promo: Codable, Equatable {
    let code: String
    let discount: Int
    let appliedAt: Date
    let sourceURL: URL
}

final class UserAccount: Codable {
    let id: String
    var promoCode: String?
    var discountPercent: Int?
    var promoAppliedAt: Date?

    init(id: String) {
        self.id = id
    }

    func applyPromo(code: String, discountPercent: Int, appliedAt: Date) {
        self.promoCode = code
        self.discountPercent = discountPercent
        self.promoAppliedAt = appliedAt
    }
}

final class PromoStore: ObservableObject {
    static let shared = PromoStore()

    @Published private(set) var currentUser: UserAccount
    @Published private(set) var lastAppliedPromo: Promo?

    private let defaults = UserDefaults.standard

    private enum Keys {
        static let userId = "promo.userId"
        static let userData = "promo.userData"
        static let lastPromo = "promo.lastPromo"
    }

    private init() {
        let userId = defaults.string(forKey: Keys.userId) ?? UUID().uuidString
        defaults.set(userId, forKey: Keys.userId)

        if let data = defaults.data(forKey: Keys.userData),
           let decoded = try? JSONDecoder().decode(UserAccount.self, from: data) {
            self.currentUser = decoded
        } else {
            self.currentUser = UserAccount(id: userId)
            persistUser()
        }

        if let data = defaults.data(forKey: Keys.lastPromo),
           let decoded = try? JSONDecoder().decode(Promo.self, from: data) {
            self.lastAppliedPromo = decoded
        } else {
            self.lastAppliedPromo = nil
        }
    }

    func applyPromo(code: String, discountPercent: Int, sourceURL: URL) {
        let now = Date()
        currentUser.applyPromo(code: code, discountPercent: discountPercent, appliedAt: now)

        let promo = Promo(code: code, discount: discountPercent, appliedAt: now, sourceURL: sourceURL)
        lastAppliedPromo = promo

        persistUser()
        persistLastPromo()
    }

    func clearLastPromo() {
        lastAppliedPromo = nil
        defaults.removeObject(forKey: Keys.lastPromo)
    }

    private func persistUser() {
        if let data = try? JSONEncoder().encode(currentUser) {
            defaults.set(data, forKey: Keys.userData)
        }
    }

    private func persistLastPromo() {
        if let promo = lastAppliedPromo,
           let data = try? JSONEncoder().encode(promo) {
            defaults.set(data, forKey: Keys.lastPromo)
        } else {
            defaults.removeObject(forKey: Keys.lastPromo)
        }
    }
}

